mapper.select:
select rr.role_code
from rbac_resource ra
         inner join rbac_role_authority rra on
    ra.id = rra.authority_id
         inner join rbac_role rr on
    rr.id = rra.role_id
where ra.tenant_id = #{tenantId}
  and rr.tenant_id = #{tenantId}
  and ra.resource_type = #{type}
  and ra.url = #{url}
  and ra.method = #{method}
  and rra.authority_type = '1'

select ra.*
from rbac_resource ra
         inner join rbac_role_authority rra on
    ra.id = rra.authority_id
         inner join rbac_role rr on
    rr.id = rra.role_id
where ra.tenant_id = #{tenantId}
  and rr.tenant_id = #{tenantId}
  and rr.role_code = #{role}
  and ra.authority_type = #{type}
  and rra.authority_type = '1'

select ra.* from rbac_resource ra

    inner join rbac_role_authority rra on rra.authority_id = ra.id
    inner join rbac_role rr on rr.role_id = r.id
    inner join rbac_user_role rur on rr.id = ur.role_Id


    ra.tenant_id = #{tenantId}
    and ra.application_id in

        #{appId}

    and ra.resource_type in

        #{type}


        and rra.authority_type = '1'
        and rr.tenant_id = #{tenantId}
        and rur.user_id = #{userId}


order by ra.application_id, ra.parent_id,ra.order_no,ra.id
